let res = [];

const allItems = $input.all();

for (const item of allItems) {
  let itemJson = item.json || {}; // 如果 item.json 是 undefined，使用空对象作为默认值
  let translatedType = ""; // 变量保存翻译后的类型

  switch (itemJson.joborder_type) {
    case "ASSY":
      translatedType = "组装";
      break;
    case "PACK":
      translatedType = "包装";
      break;
    case "AfterSale":
      translatedType = "售后";
      break;
    case "Repair":
      translatedType = "维修";
      break;
  }

  // 添加或覆盖翻译后的类型
  itemJson = {
    joborder_id: itemJson.joborder_id || "",
    joborder_number: itemJson.joborder_number || "",
    joborder_type: itemJson.joborder_type || "",
    order_number: itemJson.order_number || "",
    phase: itemJson.phase || "",
    status: itemJson.status || "",
    createtime: itemJson.createtime || "",
    product_quantity: itemJson.product_quantity || "",
    printinfobox_id: itemJson.printinfobox_id || "",
    user_name: itemJson.user_name || "",
    printinfo_name: itemJson.printinfo_name || "",
    printinfobox_name: itemJson.printinfobox_name || "",
    product_code: itemJson.product_code || "",
    procedure_list_name: itemJson.procedure_list_name || "",
    printinfo_id: itemJson.printinfo_id || "",
    product_id: itemJson.product_id || "",
    procedure_list_id: itemJson.procedure_list_id || "",
    total_count: itemJson.total_count || "",
    joborder_type_translated: translatedType,
    printinfo_second_name: itemJson.printinfo_second_name || "",
    printinfo_second_id: itemJson.printinfo_second_id || "",
  };

  res.push(itemJson);
}

return { result: res };

